import React, { useEffect, useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { dashboardAPI } from '../../services/api';
import Card from '../../components/common/Card';
import StatCard from '../../components/common/StatCard';
import { Users, ClipboardList, BookOpen, CheckCircle, User, TrendingUp, Calendar, Award, AlertTriangle } from 'lucide-react';
import toast from 'react-hot-toast';

const TeacherDashboard = () => {
  const { user } = useAuth();
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      const response = await dashboardAPI.getStats();
      if (response.data.success) {
        setStats(response.data.stats);
      }
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-20">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Welcome Header */}
      <div className="bg-gradient-to-r from-blue-600 via-blue-700 to-blue-800 rounded-2xl p-8 text-white relative overflow-hidden">
        <div className="absolute top-0 right-0 w-40 h-40 bg-white/10 rounded-full -translate-y-1/2 translate-x-1/2"></div>
        <div className="absolute bottom-0 left-1/4 w-20 h-20 bg-white/5 rounded-full translate-y-1/2"></div>
        <div className="relative z-10">
          <div className="flex items-center gap-2 text-blue-200 mb-2">
            <User className="w-5 h-5" />
            <span className="text-sm font-medium">Teacher Portal</span>
          </div>
          <h1 className="text-3xl font-bold mb-2">
            Welcome, {user?.firstName}!
          </h1>
          <p className="text-blue-100">
            {stats?.advisorySection && `Advisory: Section ${stats.advisorySection}`}
            {stats?.isCapstoneAdviser && ' | Capstone Adviser Available'}
          </p>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-5">
        <StatCard
          title="Advisory Students"
          value={stats?.advisoryCount || 0}
          icon={Users}
          color="blue"
          subtitle="Under your advisory"
        />
        <StatCard
          title="Violations Encoded"
          value={stats?.violationsEncoded || 0}
          icon={ClipboardList}
          color="orange"
          subtitle="Total recorded"
        />
        <StatCard
          title="Capstone Requests"
          value={stats?.capstoneRequests || 0}
          icon={BookOpen}
          color="purple"
          subtitle="Pending requests"
        />
        <StatCard
          title="Capstone Status"
          value={stats?.isCapstoneAdviser ? 'Available' : 'Unavailable'}
          icon={CheckCircle}
          color={stats?.isCapstoneAdviser ? 'green' : 'red'}
          subtitle="Adviser availability"
        />
      </div>

      {/* Recent Violations */}
      <Card title="Recent Violations Encoded" icon={ClipboardList}>
        {stats?.recentViolations?.length > 0 ? (
          <div className="overflow-x-auto">
            <table className="table-modern">
              <thead>
                <tr>
                  <th>Student</th>
                  <th>Violation</th>
                  <th>Date</th>
                  <th>Status</th>
                </tr>
              </thead>
              <tbody>
                {stats.recentViolations.map((violation) => (
                  <tr key={violation.id}>
                    <td>
                      <div>
                        <p className="font-medium text-secondary-800">
                          {violation.first_name} {violation.last_name}
                        </p>
                        <p className="text-xs text-secondary-500">{violation.student_id}</p>
                      </div>
                    </td>
                    <td className="text-secondary-700">{violation.violation_type}</td>
                    <td className="text-secondary-500">{violation.date}</td>
                    <td>
                      <span className={`badge ${
                        violation.status === 'Pending'
                          ? 'badge-warning'
                          : 'badge-success'
                      }`}>
                        {violation.status}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="empty-state py-12">
            <ClipboardList className="w-10 h-10" />
            <p className="text-sm">No violations encoded yet</p>
            <p className="text-xs text-secondary-400 mt-1">Start recording student violations</p>
          </div>
        )}
      </Card>
    </div>
  );
};

export default TeacherDashboard;
